# Category: metrics_exposure

import flask
from prometheus_client import generate_latest, Counter, Histogram, Gauge
import time
import json

app = flask.Flask(__name__)

# Prometheus Metrics
REQUEST_COUNT = Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['method', 'endpoint', 'status_code', 'user_id', 'api_key']
)

REQUEST_LATENCY = Histogram(
    'http_request_duration_seconds',
    'HTTP Request Latency',
    ['method', 'endpoint', 'status_code', 'user_id', 'api_key']
)

REQUEST_BODY_SIZE = Histogram(
    'http_request_body_bytes',
    'HTTP Request Body Size',
    ['method', 'endpoint', 'user_id', 'api_key']
)

ACTIVE_REQUESTS = Gauge(
    'http_active_requests',
    'Number of active HTTP requests',
    ['method', 'endpoint']
)

# A custom metric to store detailed request body information (use with caution for sensitive data)
# This is an example and might need more sophisticated handling for production
# For simplicity, we'll store a hash or a truncated version in a label if needed,
# but for full body, it's usually logged, not put in Prometheus labels directly.
# For this exercise, we'll demonstrate how to include it if it were a small, non-sensitive identifier.
# For actual request bodies, consider logging them separately or using a hash.
# Here, we'll use a simplified approach for demonstration, assuming the body is small and non-sensitive.
# In a real scenario, you'd likely hash the body or extract specific fields.
DETAILED_REQUEST_INFO = Gauge(
    'http_detailed_request_info',
    'Detailed information about specific requests (use with caution)',
    ['method', 'endpoint', 'user_id', 'api_key', 'request_body_hash']
)

@app.before_request
def before_request():
    flask.g.start_time = time.time()
    flask.g.user_id = flask.request.headers.get('X-User-ID', 'anonymous')
    flask.g.api_key = flask.request.headers.get('X-API-Key', 'none')
    flask.g.endpoint = flask.request.path
    flask.g.method = flask.request.method

    ACTIVE_REQUESTS.labels(method=flask.g.method, endpoint=flask.g.endpoint).inc()

    # Capture request body size
    if flask.request.content_length:
        REQUEST_BODY_SIZE.labels(
            method=flask.g.method,
            endpoint=flask.g.endpoint,
            user_id=flask.g.user_id,
            api_key=flask.g.api_key
        ).observe(flask.request.content_length)

    # Capture request body details (use with extreme caution for sensitive data)
    request_body = ""
    if flask.request.is_json:
        try:
            request_body = json.dumps(flask.request.json)
        except Exception:
            request_body = "invalid_json"
    elif flask.request.data:
        request_body = flask.request.data.decode('utf-8', errors='ignore')

    # For Prometheus labels, it's best to use a hash or a truncated version
    # rather than the full body, especially if it can be large or sensitive.
    # Here, we'll use a simple hash for demonstration.
    import hashlib
    request_body_hash = hashlib.sha256(request_body.encode('utf-8')).hexdigest() if request_body else 'no_body'

    # Set a gauge to 1 for the duration of the request to indicate its presence
    # This is a simplified way; for actual detailed logging, consider a separate logging system.
    # Prometheus labels should be stable and not too high cardinality.
    # Storing full request bodies in labels is generally not recommended.
    # This is for demonstration of *how* you *could* include it if it were a small identifier.
    # For actual monitoring of request bodies, you'd typically log them or extract specific fields.
    flask.g.request_body_hash = request_body_hash
    DETAILED_REQUEST_INFO.labels(
        method=flask.g.method,
        endpoint=flask.g.endpoint,
        user_id=flask.g.user_id,
        api_key=flask.g.api_key,
        request_body_hash=flask.g.request_body_hash
    ).set(1)


@app.after_request
def after_request(response):
    request_latency = time.time() - flask.g.start_time
    status_code = response.status_code

    REQUEST_COUNT.labels(
        method=flask.g.method,
        endpoint=flask.g.endpoint,
        status_code=status_code,
        user_id=flask.g.user_id,
        api_key=flask.g.api_key
    ).inc()

    REQUEST_LATENCY.labels(
        method=flask.g.method,
        endpoint=flask.g.endpoint,
        status_code=status_code,
        user_id=flask.g.user_id,
        api_key=flask.g.api_key
    ).observe(request_latency)

    ACTIVE_REQUESTS.labels(method=flask.g.method, endpoint=flask.g.endpoint).dec()

    # Reset the detailed request info gauge
    DETAILED_REQUEST_INFO.labels(
        method=flask.g.method,
        endpoint=flask.g.endpoint,
        user_id=flask.g.user_id,
        api_key=flask.g.api_key,
        request_body_hash=flask.g.request_body_hash
    ).set(0) # Set back to 0 or remove if using a different approach

    return response

@app.route('/')
def hello_world():
    return 'Hello, World!'

@app.route('/api/data', methods=['GET', 'POST'])
def api_data():
    if flask.request.method == 'POST':
        data = flask.request.json
        if data and 'value' in data:
            return flask.jsonify({"message": f"Received value: {data['value']}"}), 200
        return flask.jsonify({"error": "Invalid JSON or missing 'value'"}), 400
    return flask.jsonify({"data": "This is some API data"}), 200

@app.route('/api/user/<user_id>')
def get_user(user_id):
    # Simulate some processing time
    time.sleep(0.1)
    return flask.jsonify({"user_id": user_id, "name": f"User {user_id}"}), 200

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': 'text/plain; version=0.0.4; charset=utf-8'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)